INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (3,12,'2025-01-16 10:21:03','2025-01-16 10:21:03','This privacy policy outlines how Antiviruspoint collects, uses, and protects any information you provide while using this website.\r\n\r\nAntiviruspoint is dedicated to safeguarding your privacy. The information we request while using this website is to deliver you the best customized services and software to meet your needs. You can be assured that it will be used solely in accordance with privacy statements. We under any circumstances do not compromise your privacy.\r\n\r\nAntiviruspoint may update this policy occasionally by revising this page. We recommend checking this page periodically to stay informed about any changes. We do not send out particular emails informing you of the updated privacy policy.\r\n\r\nWe are dedicated to protecting your information. To prevent unauthorized access or disclosure, we have implemented appropriate physical, electronic, and managerial measures to safeguard and secure the data we collect online.\r\n\r\nWe will not sell, distribute, or lease your personal information to third parties unless we have your consent or are legally or contractually obligated to do so. In certain cases, we may share your personal information with the relevant software manufacturer(s) to complete the subscription activation process or as required by a distribution agreement. Additionally, if you express interest, we may use your personal information to send you promotional materials from third parties that we believe you may find relevant.\r\n<h3>The information we collect:</h3>\r\n<ul>\r\n 	<li>Name</li>\r\n 	<li>Residential Information</li>\r\n 	<li>Phone Number</li>\r\n 	<li>Credit/Debit Card Information</li>\r\n</ul>\r\n<h3>Why do we collect your information?</h3>\r\nWe collect your information to efficiently deliver and enhance our services, along with the following reasons:\r\n<ul>\r\n 	<li>To maintain internal records.</li>\r\n 	<li>To improve our products and services.</li>\r\n 	<li>To send you occasional promotional emails about new products, special offers, or other information we believe may interest you, using the email address you provided.</li>\r\n 	<li>To personalize the website experience based on your interests.</li>\r\n</ul>\r\n<h3>How do we use cookies?</h3>\r\nA cookie is a small file that requests permission to collect data while you browse. Once you accept, the file is added, and the cookie helps analyze web traffic or notifies you when you visit a specific site. Cookies allow web applications to respond to you as an individual by gathering and remembering information about your preferences, enabling the site to tailor its operations to your needs, likes, and dislikes.\r\n\r\nWe use traffic log cookies to track which pages are being visited. This helps us analyze web traffic data and improve our website services. The information collected is used solely for statistical analysis.\r\n\r\nIn general, cookies help us offer a better website experience by allowing us to monitor which pages are useful to you and which are not. Cookies do not grant us access to your computer or any personal information, other than the data you choose to share with us.\r\n\r\nYou can choose to accept or decline cookies. While most web browsers accept cookies by default, you can usually adjust your browser settings to decline them if you prefer. Please note, that declining cookies may limit your ability to fully experience the website.\r\n<h3>Links to other websites</h3>\r\nOur website may include links to other websites. However, once you click on these links and leave our site, please be aware that we have no control over the linked website. As a result, we cannot be held responsible for the protection and privacy of any information you provide while visiting these external sites, and they are not covered by this privacy policy. We recommend exercising caution and reviewing the privacy policy of the respective website.\r\n\r\nPrivacy Policy\r\n\r\nAt AntivirusPoint.org, operated by Infinity Solutions, we respect your privacy and are committed to protecting your personal data.\r\n\r\nData Collection:\r\nWe collect your name, email, phone number, and billing details only when you place an order or contact us.\r\n\r\nUsage of Data:\r\n- To process your order\r\n- To provide customer support\r\n- To improve our website and services\r\n- We do not sell or share your data with third parties, except for payment and delivery processing.\r\n\r\nCookies:\r\nWe use cookies to enhance user experience and track website usage anonymously.\r\n\r\nData Security:\r\nAll transactions are secured via SSL. We follow strict data protection practices.\r\n\r\nContact:\r\nFor data-related queries, contact us at Infinity@antiviruspoint.org','Privacy Policy','','publish','closed','open','','privacy-policy','','','2025-08-23 04:41:44','2025-08-23 04:41:44','',300553,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?page_id=3',0,'page','',0);
