INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (11,12,'2022-01-11 18:49:54','2022-01-11 18:49:54','<!-- wp:shortcode -->\r\n<p>[woocommerce_my_account]</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<!-- /wp:shortcode -->','My Account','','publish','closed','closed','','sing-register','','','2025-08-23 04:41:24','2025-08-23 04:41:24','',300553,'http://hex-wp.com/tecnoshop/my-account/',0,'page','',0);
