INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90006987,2,'2025-01-16 11:08:46','2025-01-16 11:08:46','This is a one year pre-paid subcription of Norton 360 Standard for 1 device.\r\n\r\nRenews Automatically each year. (Enrollment with Norton is required but can be cancelled at any time)\r\n\r\nEnrollment - Credit/Debit Card or PayPal required for activation (Auto-renewal direct with Norton) and can be switched off at any time after the product is activated.\r\n\r\nNorton 360 Standard includes:\r\n\r\n- Real-time Threat Protection\r\n- Secure VPN\r\n- Smart Firewall\r\n- Password Manager\r\n- 10 GB Cloud Backup\r\n- SafeCam','Norton 360 Standard - 1-Year / 1-Device - USA/Canada','Brand: Symantec / Norton\r\nMedia Type: Download\r\nPlatform: Windows 7, Windows 8, Windows 10, Windows 11, Mac OS (Current and previous two versions), Android 8 or later, iOS (Current and previous two versions)','publish','open','closed','','norton-360-standard-1-year-1-device-usa-canada','','','2025-08-20 18:50:38','2025-08-20 18:50:38','',0,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?post_type=product&#038;p=90006987',0,'product','',0);
INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90006989,2,'2025-01-16 11:08:46','2025-01-16 11:08:46','Norton 360 with LifeLock Select\nProtection from viruses, hackers, and identity thieves. A VPN to help keep your internet browsing private, plus parental control.\n\nAll-in-one protection for your devices, online privacy, and identity\n\nNorton 360 with LifeLock Select gives you comprehensive malware protection for up to 5 PC, Mac�, Android� or iOS devices, including 100GB of secure Cloud Backup and Secure VPN for all 5 devices.\n\nAlso included are features such as Parental Control to help protect your children online, and Dark Web Monitoring, where we monitor and notify you if we find your personal information on the dark web.\n\nLifeLock identity theft protection includes Stolen Wallet protection, Credit Monitoring and the LifeLock Identity Alert� System. Plus, get up to $25k in Stolen Funds Reimbursement and up to $1 million in Coverage for Lawyers and Experts if needed to help restore your identity.','Norton 360 Deluxe with LifeLock Select - 1-Year / 5-Device','Brand: Symantec\r\nMedia Type: Download\r\nPlatform: Windows 7, Windows 8, Windows 10, Windows 11, Mac OS (Current and previous two versions), Android 8 or later, iOS (Current and previous two versions)','publish','open','closed','','norton-360-deluxe-with-lifelock-select-1-year-5-device','','','2025-08-16 05:46:45','2025-08-16 05:46:45','Norton 360 with LifeLock Select\r\nProtection from viruses, hackers, and identity thieves. A VPN to help keep your internet browsing private, plus parental control.\r\n\r\nAll-in-one protection for your devices, online privacy, and identity\r\n\r\nNorton 360 with LifeLock Select gives you comprehensive malware protection for up to 5 PC, Mac�, Android� or iOS devices, including 100GB of secure Cloud Backup and Secure VPN for all 5 devices.\r\n\r\nAlso included are features such as Parental Control to help protect your children online, and Dark Web Monitoring, where we monitor and notify you if we find your personal information on the dark web.\r\n\r\nLifeLock identity theft protection includes Stolen Wallet protection, Credit Monitoring and the LifeLock Identity Alert� System. Plus, get up to $25k in Stolen Funds Reimbursement and up to $1 million in Coverage for Lawyers and Experts if needed to help restore your identity.',0,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?post_type=product&#038;p=90006989',0,'product','',0);
INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90006992,2,'2025-01-16 11:08:46','2025-01-16 11:08:46','Norton Secure VPN\r\nSecure private information like your passwords, bank details and credit card numbers when using public Wi-Fi on your PC, Mac or mobile device.\r\n\r\nWhy use Norton Secure VPN?\r\nSome VPN companies can see all the websites you visit. Choosing a brand\r\nyou can trust is paramount.\r\n\r\nNorton Secure VPN gives you:\r\n\r\nOnline privacy\r\nHelps protect your online privacy by shielding your internet data and your location from advertisers, websites and cybercriminals.\r\nCan block ad tracking technologies to avoid being tracked online by advertisers and other companies, helping to eliminate many of the targeted ads that follow you around the web.\r\nContent access\r\nCan enable global access to your favorite apps and websites while on the go, just like home.\r\nWi-Fi security\r\nLets you check email, interact on social media and pay bills using public Wi-Fi hotspots without worrying about cybercriminals intercepting the information you send and receive on a shared network.\r\nPrivacy &amp; security\r\nUses bank-grade encryption to help ensure the information you send and receive is secure and private.','Norton Secure VPN - 1-Year / 5-Device','Brand: Symantec\r\nMedia Type: Download\r\nPlatform: Windows 7, Windows 8, Windows 10, Windows 11, Mac OS (Current and previous two versions), Android 8 or later, iOS (Current and previous two versions)','publish','open','closed','','norton-secure-vpn-1-year-5-device','','','2025-08-20 18:50:38','2025-08-20 18:50:38','',0,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?post_type=product&#038;p=90006992',0,'product','',1);
