INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90007435,12,'2025-01-21 12:07:11','2025-01-21 12:07:11','<blockquote>\r\n<h2 style=\"text-align: center;\"><em><strong>No Return Policy for Antiviruspoint</strong></em></h2>\r\n</blockquote>\r\nAt Antiviruspoint, we are committed to delivering the highest quality products and services to our customers. However, due to the nature of digital products, we are unable to offer returns or refunds once the product has been activated or downloaded. Please review the following information regarding our policy.\r\n<h3>Non-refundable and Non-Returnable Products</h3>\r\nAll software licenses, digital products, and subscriptions are final sales and are not eligible for returns or refunds once activated or downloaded.\r\n<h3>Technical Issues</h3>\r\nIn the event that you experience technical issues with our software, we are happy to assist you through our support team. We will work with you to resolve any issues or concerns, but refunds or returns are not available for software that has been activated or used.\r\n\r\nReturn &amp; Refund Policy\r\n\r\nAt AntivirusPoint.org, we sell digital license keys. As such:\r\n\r\n- No refunds are offered once the license key is delivered.\r\n- If your key fails to activate, contact support for replacement or troubleshooting.\r\n\r\nExceptions:\r\nRefunds may be issued only if the product is undelivered or unusable due to technical error on our side.\r\n\r\nContact Support:\r\nEmail: Infinity@antiviruspoint.org\r\nPhone: +1-855-574-5124','Return Policy','','publish','closed','closed','','return-policy','','','2025-08-23 04:41:48','2025-08-23 04:41:48','',300553,'https://s