INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90007920,12,'2025-07-04 17:25:05','2025-07-04 17:25:05','.woocommerce span.onsale {\n  display: none !important;\n}\n/* --- Uniform Product Images --- */\n.woocommerce ul.products li.product img {\n  width: auto !important;\n  max-height: 250px !important;\n  /* fix consistent height */\n  min-height: 250px !important;\n  /* prevent very small images */\n  margin: 0 auto !important;\n  /* center images */\n  display: block !important;\n  object-fit: contain !important;\n  /* keep proportions */\n  padding: 10px;\n}\n/* --- Equal Product Card Height --- */\n.woocommerce ul.products li.product {\n  display: flex;\n  flex-direction: column;\n  justify-content: space-between;\n  min-height: 480px;\n  /* adjust until all cards look aligned */\n}\n/* --- Uniform Product Titles --- */\n.woocommerce ul.products li.product .woocommerce-loop-product__title {\n  min-height: 48px;\n  /* reserve space for 2 lines */\n  line-height: 1.3em;\n  overflow: hidden;\n  display: -webkit-box;\n  -webkit-line-clamp: 2;\n  /* max 2 lines */\n  -webkit-box-orient: vertical;\n  text-overflow: ellipsis;\n  /* add \"...\" if too long */\n  margin-bottom: 10px;\n}\n/* --- Align Price & Add-to-Cart Button --- */\n.woocommerce ul.products li.product .price, .woocommerce ul.products li.product .button {\n  margin-top: auto;\n  /* push to bottom */\n}\n','filson','','publish','closed','closed','','filson','','','2025-09-06 01:31:04','2025-09-06 01:31:04','//* Hide WooCommerce Sale Badge */\n.woocommerce span.onsale {\n    display: none !important;\n}\n/* --- Uniform Product Images --- */\n.woocommerce ul.products li.product img {\n    width: auto !important;\n    max-height: 250px !important;   /* fix consistent height */\n    min-height: 250px !important;   /* prevent very small images */\n    margin: 0 auto !important;      /* center images */\n    display: block !important;\n    object-fit: contain !important; /* keep proportions */\n    padding: 10px;\n}\n\n/* --- Equal Product Card Height --- */\n.woocommerce ul.products li.product {\n    display: flex;\n    flex-direction: column;\n    justify-content: space-between;\n    min-height: 480px;  /* adjust until all cards look aligned */\n}\n\n/* --- Uniform Product Titles --- */\n.woocommerce ul.products li.product .woocommerce-loop-product__title {\n    min-height: 48px;               /* reserve space for 2 lines */\n    line-height: 1.3em;\n    overflow: hidden;\n    display: -webkit-box;\n    -webkit-line-clamp: 2;          /* max 2 lines */\n    -webkit-box-orient: vertical;\n    text-overflow: ellipsis;        /* add \"...\" if too long */\n    margin-bottom: 10px;\n}\n\n/* --- Align Price & Add-to-Cart Button --- */\n.woocommerce ul.products li.product .price,\n.woocommerce ul.products li.product .button {\n    margin-top: auto;               /* push to bottom */\n}\n',0,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/filson/',0,'custom_css','',0);
