INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008092,12,'2025-08-15 21:06:57','2025-08-15 21:06:57','<p class=\"c-prodhero__title__size-44 c-prodhero__title\"><strong>Norton Secure VPN</strong></p>\r\n\r\n<div class=\"c-prodhero__subtitle\">\r\n\r\nSecure private information like your passwords, bank details and credit card numbers when using public Wi-Fi on your PC, Mac or mobile device.\r\n<div class=\"text aem-GridColumn--tablet--12 aem-GridColumn--phone--12 aem-GridColumn--default--9 aem-GridColumn\">\r\n<div id=\"text-text-dc441b76ec\" class=\"cmp-text \">\r\n\r\n<strong><span class=\"h1-title-2\">Why use Norton Secure VPN?</span></strong>\r\n\r\n</div>\r\n</div>\r\n<div class=\"text aem-GridColumn--tablet--12 aem-GridColumn--phone--12 aem-GridColumn--default--9 aem-GridColumn\">\r\n<div id=\"text-text-9a212cd10f\" class=\"cmp-text \">\r\n\r\nSome VPN companies can see all the websites you visit. Choosing a brand\r\nyou can trust is paramount.\r\n\r\nNorton Secure VPN gives you:\r\n\r\n</div>\r\n</div>\r\n<div class=\"container responsivegrid aem-GridColumn--tablet--12 aem-GridColumn--offset--tablet--0 aem-GridColumn--default--none aem-GridColumn--phone--none aem-GridColumn--phone--12 aem-GridColumn--tablet--none aem-GridColumn aem-GridColumn--default--8 aem-GridColumn--offset--phone--0 aem-GridColumn--offset--default--0\">\r\n<div id=\"container-ce91f6ea00\" class=\"c-container__id l-container--fullwidth c-container--fullwidth t-bg-trans\">\r\n<div class=\"c-container l-container \">\r\n<div class=\"c-container__body pb-120px \">\r\n<div class=\"aem-Grid aem-Grid--default--8 aem-Grid--phone--12 aem-Grid--tablet--12 \">\r\n<div class=\"container responsivegrid aem-GridColumn--tablet--12 aem-GridColumn--offset--tablet--0 aem-GridColumn--default--none aem-GridColumn--phone--none aem-GridColumn--phone--12 aem-GridColumn--tablet--none aem-GridColumn aem-GridColumn--offset--phone--0 aem-GridColumn--default--3 aem-GridColumn--offset--default--0\">\r\n<div id=\"container-969c41aa93\" class=\"c-container__id \">\r\n<div class=\"c-container t-bg-trans \">\r\n<div class=\"c-container__body \">\r\n<div class=\"text\">\r\n<div id=\"text-text-410cf282c3\" class=\"cmp-text \">\r\n<p style=\"text-align: left;\"><strong><span class=\"h3-title-6\">Online privacy</span></strong></p>\r\n\r\n<ul style=\"text-align: left;\">\r\n 	<li>Helps protect your online privacy by shielding your internet data and your location from advertisers, websites and cybercriminals.</li>\r\n 	<li>Can block ad tracking technologies to avoid being tracked online by advertisers and other companies, helping to eliminate many of the targeted ads that follow you around the web.</li>\r\n</ul>\r\n</div>\r\n</div>\r\n<div class=\"text\">\r\n<div id=\"text-text-4785504f5b\" class=\"cmp-text \">\r\n<p style=\"text-align: left;\"><strong><span class=\"h3-title-6\">Content access</span></strong></p>\r\n\r\n<ul>\r\n 	<li style=\"text-align: left;\">Can enable global access to your favorite apps and websites while on the go, just like home.</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"container responsivegrid aem-GridColumn--tablet--12 aem-GridColumn--offset--tablet--0 aem-GridColumn--default--none aem-GridColumn--phone--none aem-GridColumn--phone--12 aem-GridColumn--tablet--none aem-GridColumn aem-GridColumn--offset--phone--0 aem-GridColumn--default--4 aem-GridColumn--offset--default--1\">\r\n<div id=\"container-032904e6a6\" class=\"c-container__id \">\r\n<div class=\"c-container t-bg-trans \">\r\n<div class=\"c-container__body pr-lg-50px\">\r\n<div class=\"text\">\r\n<div id=\"text-text-da0404ed73\" class=\"cmp-text \">\r\n<p style=\"text-align: left;\"><strong><span class=\"h3-title-6\">Wi-Fi security</span></strong></p>\r\n\r\n<ul style=\"text-align: left;\">\r\n 	<li>Lets you check email, interact on social media and pay bills using public Wi-Fi hotspots without worrying about cybercriminals intercepting the information you send and receive on a shared network.</li>\r\n</ul>\r\n</div>\r\n</div>\r\n<div class=\"text\">\r\n<div id=\"text-text-4ed6a7d008\" class=\"cmp-text \">\r\n<p style=\"text-align: left;\"><strong><span class=\"h3-title-6\">Privacy &amp; security</span></strong></p>\r\n\r\n<ul>\r\n 	<li style=\"text-align: left;\">Uses bank-grade encryption to help ensure the information you send and receive is secure and private.</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>','Norton Secure VPN - 1-Year / 5-Device - USA/Canada','<strong>Brand:</strong> Symantec\r\n<strong>Manufacturer Part #:</strong> 21435010-USC\r\n<strong>Our Part #:</strong> AVS-21435010-USC\r\n<strong>Availability:</strong> In Stock\r\n<strong>Media Type:</strong> Download\r\n<strong>Platform:</strong> Windows 7, Windows 8, Windows 10, Windows 11, Mac OS (Current and previous two versions), Android 8 or later, iOS (Current and previous two versions)','inherit','closed','closed','','90007314-revision-v1','','','2025-08-15 21:06:57','2025-08-15 21:06:57','',90007314,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?p=90008092',0,'revision','',0);
