INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008143,12,'2025-08-23 04:41:43','2025-08-23 04:41:43','<h2>Frequently Asked Questions</h2>					<p>This Agreement was last modified on 21st January 2025\n</p>							\n					<h4 id=\"elementor-tab-title-2761\" data-tab=\"1\" role=\"button\" aria-controls=\"elementor-tab-content-2761\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\"> Can I return the software back after purchase?</a>\n					</h4>\n					<p>No. Returning software after purchase does not follow our company profile. We do not support any return policy.</p>\n					<h4 id=\"elementor-tab-title-2762\" data-tab=\"2\" role=\"button\" aria-controls=\"elementor-tab-content-2762\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\"> Do you offer hardware products and if yes, what are the shipping methods?</a>\n					</h4>\n					<p>All our products are software-based. You can download your software through our portal after the purchase process is completed.</p>\n					<h4 id=\"elementor-tab-title-2763\" data-tab=\"3\" role=\"button\" aria-controls=\"elementor-tab-content-2763\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\">How Do I Place an Order?</a>\n					</h4>\n					<p>You can place your order from our website after registering. Browse the product you need, add it to your cart, and then proceed to checkout and you are all set to go.</p>\n					<h4 id=\"elementor-tab-title-2764\" data-tab=\"4\" role=\"button\" aria-controls=\"elementor-tab-content-2764\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\">Is it compulsory to have an account for placing orders?</a>\n					</h4>\n					<p>Yes, you would need to make an account to place an order.</p>\n					<h4 id=\"elementor-tab-title-2765\" data-tab=\"5\" role=\"button\" aria-controls=\"elementor-tab-content-2765\" aria-expanded=\"false\">\n															<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H272V64c0-17.67-14.33-32-32-32h-32c-17.67 0-32 14.33-32 32v144H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h144v144c0 17.67 14.33 32 32 32h32c17.67 0 32-14.33 32-32V304h144c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n								<svg viewBox=\"0 0 448 512\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M416 208H32c-17.67 0-32 14.33-32 32v32c0 17.67 14.33 32 32 32h384c17.67 0 32-14.33 32-32v-32c0-17.67-14.33-32-32-32z\"></path></svg>\n												<a tabindex=\"0\">How often do I need to update my antivirus software?</a>\n					</h4>\n					<p>Our antivirus software automatically detects new updates and will inform you about them. You can also simply grant permission for automatic updates while setting up the software.</p>','FAQs','','inherit','closed','closed','','300654-revision-v1','','','2025-08-23 04:41:43','2025-08-23 04:41:43','',300654,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?p=90008143',0,'revision','',0);
INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008144,12,'2025-08-23 04:41:44','2025-08-23 04:41:44','This privacy policy outlines how Antiviruspoint collects, uses, and protects any information you provide while using this website.\r\n\r\nAntiviruspoint is dedicated to safeguarding your privacy. The information we request while using this website is to deliver you the best customized services and software to meet your needs. You can be assured that it will be used solely in accordance with privacy statements. We under any circumstances do not compromise your privacy.\r\n\r\nAntiviruspoint may update this policy occasionally by revising this page. We recommend checking this page periodically to stay informed about any changes. We do not send out particular emails informing you of the updated privacy policy.\r\n\r\nWe are dedicated to protecting your information. To prevent unauthorized access or disclosure, we have implemented appropriate physical, electronic, and managerial measures to safeguard and secure the data we collect online.\r\n\r\nWe will not sell, distribute, or lease your personal information to third parties unless we have your consent or are legally or contractually obligated to do so. In certain cases, we may share your personal information with the relevant software manufacturer(s) to complete the subscription activation process or as required by a distribution agreement. Additionally, if you express interest, we may use your personal information to send you promotional materials from third parties that we believe you may find relevant.\r\n<h3>The information we collect:</h3>\r\n<ul>\r\n 	<li>Name</li>\r\n 	<li>Residential Information</li>\r\n 	<li>Phone Number</li>\r\n 	<li>Credit/Debit Card Information</li>\r\n</ul>\r\n<h3>Why do we collect your information?</h3>\r\nWe collect your information to efficiently deliver and enhance our services, along with the following reasons:\r\n<ul>\r\n 	<li>To maintain internal records.</li>\r\n 	<li>To improve our products and services.</li>\r\n 	<li>To send you occasional promotional emails about new products, special offers, or other information we believe may interest you, using the email address you provided.</li>\r\n 	<li>To personalize the website experience based on your interests.</li>\r\n</ul>\r\n<h3>How do we use cookies?</h3>\r\nA cookie is a small file that requests permission to collect data while you browse. Once you accept, the file is added, and the cookie helps analyze web traffic or notifies you when you visit a specific site. Cookies allow web applications to respond to you as an individual by gathering and remembering information about your preferences, enabling the site to tailor its operations to your needs, likes, and dislikes.\r\n\r\nWe use traffic log cookies to track which pages are being visited. This helps us analyze web traffic data and improve our website services. The information collected is used solely for statistical analysis.\r\n\r\nIn general, cookies help us offer a better website experience by allowing us to monitor which pages are useful to you and which are not. Cookies do not grant us access to your computer or any personal information, other than the data you choose to share with us.\r\n\r\nYou can choose to accept or decline cookies. While most web browsers accept cookies by default, you can usually adjust your browser settings to decline them if you prefer. Please note, that declining cookies may limit your ability to fully experience the website.\r\n<h3>Links to other websites</h3>\r\nOur website may include links to other websites. However, once you click on these links and leave our site, please be aware that we have no control over the linked website. As a result, we cannot be held responsible for the protection and privacy of any information you provide while visiting these external sites, and they are not covered by this privacy policy. We recommend exercising caution and reviewing the privacy policy of the respective website.\r\n\r\nPrivacy Policy\r\n\r\nAt AntivirusPoint.org, operated by Infinity Solutions, we respect your privacy and are committed to protecting your personal data.\r\n\r\nData Collection:\r\nWe collect your name, email, phone number, and billing details only when you place an order or contact us.\r\n\r\nUsage of Data:\r\n- To process your order\r\n- To provide customer support\r\n- To improve our website and services\r\n- We do not sell or share your data with third parties, except for payment and delivery processing.\r\n\r\nCookies:\r\nWe use cookies to enhance user experience and track website usage anonymously.\r\n\r\nData Security:\r\nAll transactions are secured via SSL. We follow strict data protection practices.\r\n\r\nContact:\r\nFor data-related queries, contact us at Infinity@antiviruspoint.org','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2025-08-23 04:41:44','2025-08-23 04:41:44','',3,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?p=90008144',0,'revision','',0);
INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008145,12,'2025-08-23 04:41:45','2025-08-23 04:41:45','<!-- wp:edd/downloads {\"columns\":2} /-->','Products','','inherit','closed','closed','','90008114-revision-v1','','','2025-08-23 04:41:45','2025-08-23 04:41:45','',90008114,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?p=90008145',0,'revision','',0);
INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008146,12,'2025-08-23 04:41:47','2025-08-23 04:41:47','<!-- wp:paragraph -->\r\n<p><b>This is a sample page.</b></p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Overview</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Our refund and returns policy lasts 30 days. If 30 days have passed since your purchase, we can�t offer you a full refund or exchange.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>To be eligible for a return, your item must be unused and in the same condition that you received it. It must also be in the original packaging.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Several types of goods are exempt from being returned. Perishable goods such as food, flowers, newspapers or magazines cannot be returned. We also do not accept products that are intimate or sanitary goods, hazardous materials, or flammable liquids or gases.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Additional non-returnable items:</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:list -->\r\n<ul>\r\n<li>Gift cards</li>\r\n<li>Downloadable software products</li>\r\n<li>Some health and personal care items</li>\r\n</ul>\r\n<!-- /wp:list -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>To complete your return, we require a receipt or proof of purchase.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Please do not send your purchase back to the manufacturer.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>There are certain situations where only partial refunds are granted:</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:list -->\r\n<ul>\r\n<li>Book with obvious signs of use</li>\r\n<li>CD, DVD, VHS tape, software, video game, cassette tape, or vinyl record that has been opened.</li>\r\n<li>Any item not in its original condition, is damaged or missing parts for reasons not due to our error.</li>\r\n<li>Any item that is returned more than 30 days after delivery</li>\r\n</ul>\r\n<!-- /wp:list -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Refunds</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Once your return is received and inspected, we will send you an email to notify you that we have received your returned item. We will also notify you of the approval or rejection of your refund.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If you are approved, then your refund will be processed, and a credit will automatically be applied to your credit card or original method of payment, within a certain amount of days.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h3 class=\"wp-block-heading\">Late or missing refunds</h3>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If you haven�t received a refund yet, first check your bank account again.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Then contact your credit card company, it may take some time before your refund is officially posted.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Next contact your bank. There is often some processing time before a refund is posted.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If you�ve done all of this and you still have not received your refund yet, please contact us at {email address}.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h3 class=\"wp-block-heading\">Sale items</h3>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Only regular priced items may be refunded. Sale items cannot be refunded.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Exchanges</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>We only replace items if they are defective or damaged. If you need to exchange it for the same item, send us an email at {email address} and send your item to: {physical address}.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Gifts</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If the item was marked as a gift when purchased and shipped directly to you, you�ll receive a gift credit for the value of your return. Once the returned item is received, a gift certificate will be mailed to you.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If the item wasn�t marked as a gift when purchased, or the gift giver had the order shipped to themselves to give to you later, we will send a refund to the gift giver and they will find out about your return.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Shipping returns</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>To return your product, you should mail your product to: {physical address}.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>You will be responsible for paying for your own shipping costs for returning your item. Shipping costs are non-refundable. If you receive a refund, the cost of return shipping will be deducted from your refund.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Depending on where you live, the time it may take for your exchanged product to reach you may vary.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>If you are returning more expensive items, you may consider using a trackable shipping service or purchasing shipping insurance. We don�t guarantee that we will receive your returned item.</p>\r\n<!-- /wp:paragraph -->\r\n\r\n<!-- wp:heading -->\r\n<h2 class=\"wp-block-heading\">Need help?</h2>\r\n<!-- /wp:heading -->\r\n\r\n<!-- wp:paragraph -->\r\n<p>Contact us at {email} for questions related to refunds and returns.</p>\r\n<!-- /wp:paragraph -->','Refund and Returns Policy','','inherit','closed','closed','','14-revision-v1','','','2025-08-23 04:41:47','2025-08-23 04:41:47','',14,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?p=90008146',0,'revision','',0);
INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008147,12,'2025-08-23 04:41:48','2025-08-23 04:41:48','<blockquote>\r\n<h2 style=\"text-align: center;\"><em><strong>No Return Policy for Antiviruspoint</strong></em></h2>\r\n</blockquote>\r\nAt Antiviruspoint, we are committed to delivering the highest quality products and services to our customers. However, due to the nature of digital products, we are unable to offer returns or refunds once the product has been activated or downloaded. Please review the following information regarding our policy.\r\n<h3>Non-refundable and Non-Returnable Products</h3>\r\nAll software licenses, digital products, and subscriptions are final sales and are not eligible for returns or refunds once activated or downloaded.\r\n<h3>Technical Issues</h3>\r\nIn the event that you experience technical issues with our software, we are happy to assist you through our support team. We will work with you to resolve any issues or concerns, but refunds or returns are not available for software that has been activated or used.\r\n\r\nReturn &amp; Refund Policy\r\n\r\nAt AntivirusPoint.org, we sell digital license keys. As such:\r\n\r\n- No refunds are offered once the license key is delivered.\r\n- If your key fails to activate, contact support for replacement or troubleshooting.\r\n\r\nExceptions:\r\nRefunds may be issued only if the product is undelivered or unusable due to technical error on our side.\r\n\r\nContact Support:\r\nEmail: Infinity@antiviruspoint.org\r\nPhone: +1-855-574-5124','Return Policy','','inherit','closed','closed','','90007435-revision-v1','','','2025-08-23 04:41:48','2025-08-23 04:41:48','',90007435,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?p=90008147',0,'revision','',0);
INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008148,12,'2025-08-23 04:41:50','2025-08-23 04:41:50','<h1>Terms &amp; Conditions</h1><p>Refund Policy</p><p>Due to the nature of digital distribution of active license codes, Antiviruspoint can not offer refunds or exchanges for products once delivered and activation/license key has been viewed. All licensing sales are final.</p><p>You may <strong>request a refund</strong> if you have <strong>not yet retrieved</strong> the activation/license key from our system. If you have already retrieved the activation/license key, <strong>NO REFUNDS</strong> will be granted. Please make sure the software works on your system before retrieving the activation/license key.</p><p>Use of Website</p><p>By using the Antiviruspoint website (\"Website\"), you agree to the following terms and conditions of use (\"Terms\") and assume full responsibility and risk for your use of this Site and any services or information contained herein. If you do not agree to the Terms of this Website, you should immediately stop utilizing this Website.</p><p>By using this Website, you acknowledge that the content here, including these Terms, may change at any time without any requirement on the part of Antiviruspoint to provide notification prior to the changes nor notification after the fact. All users are responsible for reviewing the Terms and content of this Website for changes. Your continued use of this Website after any modification to the Terms or content of this Website shall be construed as your acceptance of the revisions.</p><p>By using this Website, you agree that you will use any services or content of this Website for lawful purposes only. You are prohibited from using this Website to acquire, transfer, store or otherwise move any information, data, content, or material in violation of any US, Canadian or international law (including law pertaining to intellectual property).</p><p>By using this Website, you agree that you will not use any services or content of this Website for any commercial purposes without explicit written permission from Antiviruspoint. Conditional exceptions for the commercial use of this Website are granted to Antiviruspoint members currently in good standing; please consult the Antiviruspoint membership terms for more information.</p><p>Antiviruspoint Website User Account</p><p>An Antiviruspoint Website user account is necessary to fully access the services and content available through this Website. Having a user account for this Website alone does not represent membership within Antiviruspoint. Your having an active and valid user account for this Website does not make you an Antiviruspoint member. However, any official Antiviruspoint membership status may be displayed through your user account.</p><p>By signing up for a Website user account, you agree to provide all information required by the signup process factually and only information pertaining to your own self. It is prohibited to provide third-party information or false information to Antiviruspoint or through this Website in an attempt to impersonate a party you are not legally authorized to represent. You may also not use another\'s party\'s account, nor may you allow another party to use your account to access content or services that require a user account to access.</p><p>By signing up for a Website user account, you agree to assume full responsibility for all activities that occur on or through your account. It is therefore imperative that you keep your account information secure. Any breach of your account\'s security, such as the theft of your password, must be immediately reported to Antiviruspoint. Antiviruspoint reserves the right to, at its sole discretion, terminate (including: ban, delete, etc) your user account without prior notice for any reasons included within these Terms or otherwise.</p><p>By signing up for a Website user account, you agree that you have no actual ownership of your account or any portion of this Website. Antiviruspoint may, at its discretion and without prior notice, remove any or all material submitted by your account (including the account itself) for reasons including but not limited to: violation of these Terms, violation of US, Canadian or international law, troublemaking, etc. Antiviruspoint assumes no liability for any content or service removed from our site, whether it originated from Antiviruspoint or a Website user account, and reserves the right to permanently restrict or block access to the Website or a user account. By using this Website, you agree that Antiviruspoint will have no liability to you if this Website and its content and services are discontinued to you or in general.</p><p>Ownership of Website Content and Intellectual Property</p><p>The content and intellectual property on this Website belongs to Antiviruspoint or attributed Antiviruspoint content providers and licensees and protected under Canadian and international law. Content includes but is not limited to: information, data, images, video, trademarks, service marks, industrial designs, logo, and other material and services, both copyrighted and non-copyrighted.</p><p>\"Antiviruspoint\" and all associated trademarks, service marks, ownership designations and logos are the property of Antiviruspoint. Such markings may not be used without the explicit written permission of Antiviruspoint. You may not combine or otherwise modify Antiviruspoint markings to affiliate the Antiviruspoint markings with that of another party to imply a relationship between Antiviruspoint and the other party. All other trademarks, logos or slogans not owned by \"Antiviruspoint\" that appear on this website are the property of their respective owners, who may or may not be affiliated with, connected to, or sponsored by \"Antiviruspoint\".</p><p>The content of this Website may not be reproduced, downloaded, screen captured, disseminated, published or otherwise transferred in any form or by any means, without the explicit written permission of Antiviruspoint. Unauthorized activities involving Antiviruspoint Website content may be a violation of Canadian or international law, and subject to criminal and civil prosecution. By visiting this Website, you do not acquire or obtain by implication or otherwise, any license or right or permission to use or make additional copies of any Antiviruspoint Website content. You agree not to display or make use of any Antiviruspoint Website content in any manner, including but not limited to for commercial purpose, without explicit written permission from Antiviruspoint.</p><p>User Submissions</p><p>By submitting material for display on the Antiviruspoint Website, you agree not to submit any content that is illegal, indecent, profane (either directly or indirectly through partially obscured words, letters, phrases, terminology or similar wording), threatening, defamatory, derogatory, or otherwise injurious to Antiviruspoint or third parties. No business solicitation may be made on the Antiviruspoint website without explicit written permission from Antiviruspoint.</p><p>You also agree that you will not provide personal or confidential information about third parties, or infringe on the privacy rights or dignity of third parties. You further agree that you will not submit materials that consist of or is intended to support, disseminate or otherwise promote malicious software code, including unsolicited electronic mass mailing (\"spam\"), regardless of the intention or message of the activity or material. As with Website User Account, submission of material to Antiviruspoint may not involve any attempt to misrepresentation affiliation or standing with Antiviruspoint or any third party, and may not involve the impersonation of any Antiviruspoint personnel or any third party.</p><p>All material you submit to Antiviruspoint become the property of Antiviruspoint without any onus on the part of Antiviruspoint to provide any acknowledgement for your submission. You hereby grant to Antiviruspoint a non-exclusive, royalty-free, perpetual, irrevocable, fully transferable, sub-licensable and assignable right to use, edit, modify, adapt, translate, edit, and reformate any material in which you may be deemed to continue to hold any ownership right as necessary and for any purpose, anywhere in the world, including into those forms that may constitute advertising.</p><p>By using this Website, creating an Antiviruspoint Website user account, and otherwise posting or submitting content to Antiviruspoint, you understand and agree that any material, ideals or communications you transmit in any manner and for any reason will not be treated as confidential or proprietary.</p><p>You understand and agree that you will avoid submitting any suggestions, materials, ideas or creative concepts for new, modified or different products or services to this Website. Failure to comply will result in the unsolicited material being deemed to be the full property of Antiviruspoint with all associated rights and privileges, without compensation to you. Antiviruspoint shall not be liable for the open disclosure or use of unsolicited material for commercial purposes or otherwise.</p><p>Professional Certifications</p><p>The various levels and specializations for Antiviruspoint certification is awarded to those businesses or individuals that have successfully completed the relevant Antiviruspoint training or Antiviruspoint recognized equivalency. The certifications are not permanent and must be maintained through regular verified technical service activities. Antiviruspoint is not responsible for the conduct or the quality of services provided of any business or their employees that may have earned or displays any Antiviruspoint certifications.</p><p>Disclaimer &amp; Limitation of Liability</p><p>Antiviruspoint strives to ensure that the content of this Website is accurate and reliable. RESPONSIBLE FOR ANY DAMAGES WHATSOEVER THAT RESULT FROM MISTAKES, OMISSIONS, INTERRUPTIONS, DELETION OF FILES, ERRORS, DEFECTS, DELAYS IN OPERATION OR TRANSMISSION, OR ANY FAILURE OF PERFORMANCE WHETHER OR NOT CAUSED BY EVENTS BEYOND Antiviruspoint\' REASONABLE CONTROL, INCLUDING BUT NOT LIMITED TO ACTS OF GOD, COMMUNICATIONS LINE FAILURE, THEFT, DESTRUCTION, OR UNAUTHORIZED ACCESS TO THIS SITE\'S RECORDS, PROGRAMS, OR SERVICES. IN NO EVENT SHALL Antiviruspoint\' TOTAL LIABILITY FOR ALL DAMAGES, LOSSES, AND CASES OF ACTION EXCEED FIVE DOLLARS (US $5). SOME JURISDICTIONS DO NOT ALLOW THE LIMITATION OR EXCLUSION OF LIABILITY FOR INCIDENTAL OR CONSEQUENTIAL DAMAGES; AS A RESULT, THE ABOVE LIMITATION OR EXCLUSION MAY NOT APPLY TO YOU.</p><p>By using this Website, you understand and agree that any reliance on any content or service on this Website will be at your own risk. Antiviruspoint makes no representation regarding the length of time that any content will be preserved or otherwise stored or displayed. Antiviruspoint reserves the right to revise the content and services of this Website without notification to past, present for prospective visitors or users. Under no circumstances shall Antiviruspoint be liable for any indirect, special, incidental, or consequential damages arising out of any use of the content or services of this Website.</p><p>Privacy Statement</p><p>This Website has features a privacy statement setting forth how information collected about you is collected, used and stored. Your use of this Website constitutes understanding and agreement with our Privacy Statement. You further acknowledge and agree that the Website may use your personal information in the manner described in or Privacy Statement.</p><p>Third Party Website</p><p>This Website may be linked to third-party websites which are not owned by, maintained by, known by or affiliated with Antiviruspoint. Antiviruspoint does not sponsor, endorse, approve, certify, or control those websites and is not responsible for the contents of such sites. Those sites contain information created, published, maintained, or otherwise posted by institutions or organizations independent of Antiviruspoint. Antiviruspoint makes no representations or warranties about the content, completeness, or accuracy of those third party sites or information located on such sites. Such links does not constitute or imply endorsement, recommendation, or favoring by Antiviruspoint.</p><p>Furthermore, Antiviruspoint is not responsible for the privacy practices of such other sites. The information you submit at a third party site accessible from this Website is subject to the terms of that site\'s privacy policy, and Antiviruspoint has no control over how your information is collected, used, or otherwise handled. Access to any other websites linked to or from the Antiviruspoint site is at your own discretion and risk.</p><p>Indemnification</p><p>You agree to indemnify and hold Antiviruspoint, its parents, subsidiaries, officers, employees, agents, licensors, representatives, and third-party providers to this Website harmless for any claims, damages and, expenses, including reasonable attorneys\' fees and costs, related to violation of these Terms or unlawful or abusive behavior, including the infringement of any intellectual property or privacy rights of any person, or any violations thereof by your dependants.</p><p>The above is included in the Terms and Conditions at checkout, by acknowledging them, you the buyer agree to them and therefore take full responsibility for any products purchased from Antiviruspoint..</p><p>Both you and Antiviruspoint acknowledge and agree that no partnership is formed and neither of you nor Antiviruspoint has the power or the authority to obligate or bind the other. These Terms constitute a binding agreement between you and Antiviruspoint, and is accepted by you upon your use of this Website. These Terms constitute the entire agreement between you and Antiviruspoint regarding the use of this Website.</p><p>This Agreement will be governed by and construed in accordance with US and  Canadian law without regard to conflicts of laws principles. By using this Website, you hereby agree that any and all disputes regarding these Terms will be subject to US and Canadian law. These Terms operate to the fullest extent permissible by law. If any provision of these Terms is unlawful, void or unenforceable, that provision is deemed severable from these Terms and does not affect the validity and enforceability of any remaining provisions.</p><p>Although Antiviruspoint will not be liable for your losses caused by any unauthorized use of your account, you may be liable for the losses of Antiviruspoint or others due to such unauthorized use. If Antiviruspoint fails to act with respect to your breach or anyone else\'s breach on any occasion, Antiviruspoint is not waiving its right to act with respect to future or similar breaches.</p><p>Errors on Our Site</p><p>We try to be as accurate as possible. However, we do not warrant that product descriptions or other Site content is accurate, complete, reliable, current, or error-free. Prices and promotions are subject to change. Despite our best efforts, rarely an item in our catalog may not be available, the offer may have been misstated, or an item may be mispriced. For any of these reasons, we may cancel your order or we may contact you for instructions on the order.</p><p>Order Confirmation</p><p>Our order confirmation to you does not signify our acceptance of your order, nor does it constitute confirmation of our offer to sell. At any time after receipt of your order, we may accept, decline, or place quantity or other limits on your order for any reason. We may impose these limits on a per-person, per-household, per-order, or any other basis. If we reject, limit, or otherwise modify your order, we will attempt to notify you using the e-mail address you provide to us. If we cancel an order or part of an order that we\'ve already charged you for, we\'ll refund you the full amount of the canceled portion of the order.</p><p>The headings in these Terms are for your convenience and reference. These headings do not limit or affect these Terms. These Terms, together with those items made a part of these terms by reference, make up the entire agreement between you and Antiviruspoint relating to this Website, and replace any prior understandings or agreements (whether oral or written) regarding this Website. If a court finds any of these terms to be unenforceable or invalid, that term will be enforced to the fullest extent permitted by applicable law and the other terms will remain valid and enforceable. This Website and any promotions contained thereon are void where prohibited.</p><p>Privacy Policy</p><p>At AntivirusPoint.org, operated by Infinity Solutions, we respect your privacy and are committed to protecting your personal data.</p><p>Data Collection: <br />We collect your name, email, phone number, and billing details only when you place an order or contact us.</p><p>Usage of Data: <br />- To process your order <br />- To provide customer support <br />- To improve our website and services <br />- We do not sell or share your data with third parties, except for payment and delivery processing.</p><p>Cookies: <br />We use cookies to enhance user experience and track website usage anonymously.</p><p>Data Security: <br />All transactions are secured via SSL. We follow strict data protection practices.</p><p>Terms &amp; Conditions</p><p>By purchasing from AntivirusPoint.org, you agree to the following terms:</p><p>Products: <br />We sell digital antivirus license keys for software activation. No physical product is shipped.</p><p>Delivery: <br />License keys are delivered via email immediately after successful payment.</p><p>Usage: <br />Keys are for personal or business use as per the software vendor’s licensing terms.</p><p>Liability: <br />Infinity Solutions is not responsible for misuse of keys or software beyond the original licensing terms.</p><p>Jurisdiction: <br />All disputes are subject to the jurisdiction of Jaipur, Rajasthan, India.</p><p>Contact: <br />Email: Infinity@antiviruspoint.org | Phone: +1-855-574-5124</p><p>By using this Website, you understand that these Terms constitute a binding Agreement between you and Antiviruspoint.</p>','Terms and Conditions','','inherit','closed','closed','','90007011-revision-v1','','','2025-08-23 04:41:50','2025-08-23 04:41:50','',90007011,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?p=90008148',0,'revision','',0);
