INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008150,12,'2025-08-23 05:51:30','2025-08-23 05:51:30','.hw-nav-cat-menu.hw-cat-sub.hw-cat-active > li > .hw-cat-drop {\n    display: none !important;\n}\n/* === Keep only WhatsApp + Email share icons, hide all others === */\n\n/* Hide all share icons by default */\n.woocommerce div.product .social-icons a {\n    display: none !important;\n}\n\n/* Show only WhatsApp + Email */\n.woocommerce div.product .social-icons a[href*=\"whatsapp\"],\n.woocommerce div.product .social-icons a[href*=\"mailto\"] {\n    display: inline-block !important;\n}\n\n\n','filson','','inherit','closed','closed','','90007920-revision-v1','','','2025-08-23 05:51:30','2025-08-23 05:51:30','',90007920,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?p=90008150',0,'revision','',0);
INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008159,12,'2025-08-23 07:58:34','2025-08-23 07:58:34','{\n    \"custom_css[filson]\": {\n        \"value\": \"/* Hide all share icons by default */\\n.woocommerce div.product .social-icons a {\\n  display: none !important;\\n}\\n\\n/* Show only WhatsApp */\\n.woocommerce div.product .social-icons a[href*=\\\"9543364969\\\"] {\\n  display: inline-flex !important;\\n  margin-right: 12px;\\n  font-size: 20px;\\n  color: #25D366; /* WhatsApp Green */\\n}\\n\\n/* Show only Email */\\n.woocommerce div.product .social-icons a[href^=\\\"mailto:infinity@antiviruspoint.org\\\"] {\\n  display: inline-flex !important;\\n  margin-right: 12px;\\n  font-size: 20px;\\n  color: #0072c6; /* Email Blue */\\n}\\n\\n/* Show only Instagram */\\n.woocommerce div.product .social-icons a[href*=\\\"instagram.com/antivirus.point\\\"] {\\n  display: inline-flex !important;\\n  margin-right: 12px;\\n  font-size: 20px;\\n  color: #E1306C; /* Instagram Pink */\\n}\\n\\n/* Hover Effect (Optional, looks professional) */\\n.woocommerce div.product .social-icons a:hover {\\n  transform: scale(1.2);\\n  opacity: 0.8;\\n}\\n\\n\",\n        \"type\": \"custom_css\",\n        \"user_id\": 12,\n        \"date_modified_gmt\": \"2025-08-23 07:58:34\"\n    }\n}','','','publish','closed','closed','','06d1471f-ca74-4f5c-ac50-4107c8c4f862','','','2025-08-23 07:58:34','2025-08-23 07:58:34','',0,'https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com/?p=90008159',0,'customize_changeset','',0);
