INSERT INTO `fqsi_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (90008295,12,'2025-09-06 01:28:48','2025-09-06 01:28:48','{\n    \"custom_css[filson]\": {\n        \"value\": \"//* Hide WooCommerce Sale Badge */\\n.woocommerce span.onsale {\\n    display: none !important;\\n}\\n/* Hide 2nd hover image in shop grid */\\n.woocommerce ul.products li.product .secondary-image {\\n    display: none !important;\\n}\\n/* --- Uniform Product Images --- */\\n.woocommerce ul.products li.product img {\\n    width: auto !important;\\n    max-height: 250px !important;   /* fix consistent height */\\n    margin: 0 auto !important;      /* center horizontally */\\n    display: block !important;\\n    object-fit: contain !important; /* no stretch */\\n    padding: 10px;\\n}\\n\\n/* --- Equal Product Card Height --- */\\n.woocommerce ul.products li.product {\\n    min-height: 420px;   /* adjust based on your design */\\n    display: flex;\\n    flex-direction: column;\\n    justify-content: space-between;\\n}\\n\\n/* --- Uniform Product Titles --- */\\n.woocommerce ul.products li.product .woocommerce-loop-product__title {\\n    min-height: 48px;               /* reserve space for 2 lines */\\n    line-height: 1.3em;\\n    overflow: hidden;\\n    display: -webkit-box;\\n    -webkit-line-clamp: 2;          /* limit to 2 lines */\\n    -webkit-box-orient: vertical;\\n    text-overflow: ellipsis;        /* add \\\"...\\\" if too long */\\n}\\n\",\n        \"type\": \"custom_css\",\n        \"user_id\": 12,\n        \"date_modified_gmt\": \"2025-09-06 01:28:48\"\n    }\n}','','','publish','closed','closed','','198f7696-f3e4-414d-a478-487b49d1eec0','','','2025-09-06 01:28:48','2025-